I'm having some trouble using crochet with twisted's spawnProcess. The process seems to run when just using twisted, but with crochet, only the protocol's connectionMade function is ever called and the script exits. Am I doing something wrong?

    from crochet import setup, run_in_reactor
    from twisted.internet import reactor
    
    class BareQDAL41xBFactory(Factory):
        def __init__(self):
            self.instances = []

        def buildProtocol(self, port=None, buffer_size=100):
            instance = ProtocolBareQDAL41xB(buffer_size=buffer_size)
            reactor.spawnProcess(instance, BIN_PATH, [BIN_NAME], {})
            return instance

    factory = BareQDAL41xBFactory()

    @run_in_reactor
    def run():
        protocol = factory.buildProtocol()
        return protocol

    # This does not work
    if __name__ == '__main__':
        setup()
        run()

    # This does
    if __name__ == '__main__':
        protocol = factory.buildProtocol()
        reactor.run()

